patches.fixed_method:
static boolean isSimpleNumber(String s) {
  int len = s.length();
  for (int index = 0; index < len; index++) {
    char c = s.charAt(index);
    if (!Character.isDigit(c)) {
      return false;
    } else if (index == 0 && c == '0' && len > 1) {
      return false;
    }
  }
  return len > 0;
}

